/// # Arguments
/// - `rd` — Destination register.
/// - `rs1` — Source register.
/// - `shamtw` — Immediate encoding value.
pub trait BinviRv32Emitter<T0, T1, T2> {
    fn binvi_rv32(&mut self, rd: T0, rs1: T1, shamtw: T2);
}

