/// - `rd` — Destination register.
/// - `rs1` — Source register.
/// - `rm` — Rounding mode.
pub trait FcvtWSEmitter<T0, T1, T2> {
    fn fcvt_w_s(&mut self, rd: T0, rs1: T1, rm: T2);
}

