    ///   * `Store/AMO Access Fault` if a PMP or PMA access check fails.
    ///
    /// &lt;%- if CACHE_BLOCK_SIZE.bit_length &lt;= \[PMP_GRANULARITY, PMA_GRANULARITY\].min -%&gt;
